import React, { useEffect, useState } from "react";
import axios from "axios";
import API_BASE from "../api";
import { useNavigate } from "react-router-dom";

export default function PredictionPage() {
  const [symptoms, setSymptoms] = useState([]);
  const [selected, setSelected] = useState({});
  const navigate = useNavigate();

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    axios.get(`${API_BASE}/symptoms`)
      .then((res) => setSymptoms(res.data.symptoms || []))
      .catch(() => alert("Failed to load symptoms"));
  }, []);

  const handleCheckbox = (symptom) => {
    setSelected({
      ...selected,
      [symptom]: selected[symptom] ? 0 : 1
    });
  };

  const handlePredict = async () => {
    try {
      const res = await axios.post(`${API_BASE}/predict`, {
        patient_name: user?.name,
        patient_email: user?.email,
        symptoms: selected
      });

      localStorage.setItem("predictionResult", JSON.stringify(res.data));
      navigate("/result");
    } catch (err) {
      alert(err.response?.data?.error || "Prediction failed");
    }
  };

  return (
    <div className="dashboard-page">
      <div className="dashboard-card">
        <h2>Select Symptoms</h2>
        <div className="symptom-grid">
          {symptoms.map((symptom, index) => (
            <label key={index} className="symptom-item">
              <input
                type="checkbox"
                checked={selected[symptom] === 1}
                onChange={() => handleCheckbox(symptom)}
              />
              {symptom.replaceAll("_", " ")}
            </label>
          ))}
        </div>
        <button onClick={handlePredict}>Predict Disease</button>
      </div>
    </div>
  );
}
